class Solution:
    def slidingPuzzle(self, board):
        from collections import deque
        start = ''.join(str(c) for row in board for c in row)
        goal = '123450'
        neighbors = {0: [1, 3], 1: [0, 2, 4], 2: [1, 5], 3: [0, 4], 4: [1, 3, 5], 5: [2, 4]}
        seen = {start}
        q = deque([(start, 0)])
        while q:
            state, d = q.popleft()
            if state == goal:
                return d
            z = state.index('0')
            for nb in neighbors[z]:
                lst = list(state)
                lst[z], lst[nb] = lst[nb], lst[z]
                ns = ''.join(lst)
                if ns not in seen:
                    seen.add(ns)
                    q.append((ns, d + 1))
        return -1

