var slidingPuzzle = function(board) {
    const start = board.flat().join('');
    const goal = '123450';
    const adj = [[1, 3], [0, 2, 4], [1, 5], [0, 4], [1, 3, 5], [2, 4]];
    const visited = new Set([start]);
    let queue = [[start, 0]];
    while (queue.length) {
        const next = [];
        for (const [state, dist] of queue) {
            if (state === goal) return dist;
            const z = state.indexOf('0');
            for (const nb of adj[z]) {
                const s = state.split('');
                [s[z], s[nb]] = [s[nb], s[z]];
                const t = s.join('');
                if (!visited.has(t)) {
                    visited.add(t);
                    next.push([t, dist + 1]);
                }
            }
        }
        queue = next;
    }
    return -1;
};
